var skillName = "active.change_plates";
var skillOpt = Templates.All<SkillTemplate>().FirstOrDefault(s => s.name == skillName);
Assert.NotNull(skillOpt, $"Skill/Perk '{skillName}' should exist");
skillOpt

var handlers = skillOpt.EventHandlers;
Assert.NotNull(handlers, "EventHandlers should not be null");
Assert.True(handlers.Count > 0, "Should have at least one EventHandler");
var handler = handlers.FirstOrDefault(h => h._type == "RestoreArmorDurability");
Assert.NotNull(handler, $"Should find RestoreArmorDurability EventHandler");
handler

var fieldValue = handler.RestorePercent;
Assert.NotNull(fieldValue, "RestorePercent should be populated");
fieldValue
